import React, { useEffect, useState } from "react";
import Button from "@material-ui/core/Button";
import Dialog from "@material-ui/core/Dialog";
import DialogActions from "@material-ui/core/DialogActions";
import DialogContent from "@material-ui/core/DialogContent";
import DialogTitle from "@material-ui/core/DialogTitle";
import Typography from "@material-ui/core/Typography";
import Alert from "@material-ui/lab/Alert";
import {
  LAMPORTS_PER_SOL,
  PublicKey,
  SystemProgram,
  Transaction,
} from "@solana/web3.js";
import { useConnection, useWallet } from "@solana/wallet-adapter-react/lib/cjs";
import FreebayAPI from "../../Api";

function formatTimeLeft(expiresAt) {
  const ms = new Date(expiresAt).getTime() - Date.now();
  if (ms <= 0) return "Expired";

  const totalSeconds = Math.floor(ms / 1000);
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  return `${minutes}:${seconds.toString().padStart(2, "0")}`;
}

export default function PaymentModal({ open, productWon, onClose, onInvoiceUpdate }) {
  const { connection } = useConnection();
  const { publicKey, sendTransaction, connected, connect, select, wallet, wallets } = useWallet();
  const [invoice, setInvoice] = useState(productWon && productWon.invoice);
  const [timeLeft, setTimeLeft] = useState(
    productWon && productWon.invoice ? formatTimeLeft(productWon.invoice.expiresAt) : ""
  );
  const [isPaying, setIsPaying] = useState(false);
  const [error, setError] = useState("");
  const [txSignature, setTxSignature] = useState("");

  useEffect(() => {
    setInvoice(productWon && productWon.invoice);
    setTxSignature("");
    setError("");
  }, [productWon]);

  useEffect(() => {
    if (!open || !invoice || invoice.status !== "pending") return undefined;

    const timer = setInterval(() => {
      setTimeLeft(formatTimeLeft(invoice.expiresAt));
    }, 1000);

    return () => clearInterval(timer);
  }, [open, invoice]);

  useEffect(() => {
    if (!open || !invoice || invoice.status !== "pending") return undefined;

    const poller = setInterval(async () => {
      try {
        const updatedInvoice = await FreebayAPI.getInvoice(invoice.id);
        setInvoice(updatedInvoice);
        if (updatedInvoice.status !== "pending" && onInvoiceUpdate) {
          onInvoiceUpdate(updatedInvoice);
        }
      } catch (err) {
        setError("Unable to refresh invoice status");
      }
    }, 3000);

    return () => clearInterval(poller);
  }, [open, invoice, onInvoiceUpdate]);

  async function handlePayNow() {
    if (!invoice) return;

    setError("");
    setIsPaying(true);

    try {
      if (!wallet) {
        const phantom = wallets.find((w) => w.adapter.name === "Phantom");
        if (phantom) select(phantom.adapter.name);
      }

      if (!connected) await connect();
      if (!publicKey) throw new Error("Connect your Phantom wallet first");

      const transaction = new Transaction().add(
        SystemProgram.transfer({
          fromPubkey: publicKey,
          toPubkey: new PublicKey(invoice.paymentAddress),
          lamports: Math.round(Number(invoice.amountSOL) * LAMPORTS_PER_SOL),
        })
      );

      const signature = await sendTransaction(transaction, connection);
      setTxSignature(signature);
      await connection.confirmTransaction(signature, "confirmed");
    } catch (err) {
      setError(err.message || "Payment failed");
    } finally {
      setIsPaying(false);
    }
  }

  if (!productWon || !invoice) return null;

  const confirmed = invoice.status === "confirmed";
  const expired = invoice.status === "expired" || timeLeft === "Expired";

  return (
    <Dialog open={open} onClose={onClose} maxWidth="sm" fullWidth>
      <DialogTitle>Pay for won auction</DialogTitle>
      <DialogContent>
        <Typography variant="subtitle1">{productWon.name}</Typography>
        <Typography variant="body2" color="textSecondary">
          Auction price: ${Number(invoice.amountUSD).toFixed(2)}
        </Typography>
        <br />
        {confirmed ? (
          <Alert severity="success">Payment Confirmed</Alert>
        ) : expired ? (
          <Alert severity="error">Invoice expired</Alert>
        ) : (
          <Alert severity="info">Send exactly {invoice.amountSOL} SOL on Solana devnet.</Alert>
        )}
        <br />
        <Typography variant="body2">Amount SOL: {invoice.amountSOL}</Typography>
        <Typography variant="body2" style={{ overflowWrap: "anywhere" }}>
          Payment address: {invoice.paymentAddress}
        </Typography>
        <Typography variant="body2">Time left: {timeLeft}</Typography>
        {txSignature ? (
          <Typography variant="body2" style={{ overflowWrap: "anywhere" }}>
            Submitted transaction: {txSignature}
          </Typography>
        ) : null}
        {error ? (
          <>
            <br />
            <Alert severity="error">{error}</Alert>
          </>
        ) : null}
      </DialogContent>
      <DialogActions>
        <Button onClick={onClose}>Close</Button>
        <Button
          onClick={handlePayNow}
          color="primary"
          variant="contained"
          disabled={confirmed || expired || isPaying}
        >
          {isPaying ? "Sending" : "Pay Now"}
        </Button>
      </DialogActions>
    </Dialog>
  );
}
