import React, { useState } from "react";
import Button from "@material-ui/core/Button";
import { useWallet } from "@solana/wallet-adapter-react/lib/cjs";

function shortenAddress(address) {
  if (!address) return "";
  return `${address.slice(0, 4)}...${address.slice(-4)}`;
}

export default function ConnectWalletButton({ className }) {
  const { publicKey, connect, disconnect, connected, connecting, select, wallet, wallets } =
    useWallet();
  const [error, setError] = useState("");

  async function handleClick() {
    setError("");

    try {
      if (connected) {
        await disconnect();
        return;
      }

      if (!wallet) {
        const phantom = wallets.find((w) => w.adapter.name === "Phantom");
        if (phantom) select(phantom.adapter.name);
      }

      await connect();
    } catch (err) {
      setError("Wallet unavailable");
    }
  }

  const label = connected
    ? shortenAddress(publicKey.toBase58())
    : connecting
    ? "Connecting"
    : "Connect Wallet";

  return (
    <Button color="default" className={className} onClick={handleClick} title={error}>
      {label}
    </Button>
  );
}
