import React from 'react';
import ReactDOM from 'react-dom';
import App from './App';
import reportWebVitals from './reportWebVitals';
import { BrowserRouter } from 'react-router-dom';
import { ConnectionProvider, WalletProvider } from "@solana/wallet-adapter-react/lib/cjs";
import { PhantomWalletAdapter } from "@solana/wallet-adapter-phantom/lib/cjs";

const solanaEndpoint =
  process.env.REACT_APP_SOLANA_RPC_URL || "https://api.devnet.solana.com";
const wallets = [new PhantomWalletAdapter()];

ReactDOM.render(
  <React.StrictMode>
    <ConnectionProvider endpoint={solanaEndpoint}>
      <WalletProvider wallets={wallets} autoConnect>
        <BrowserRouter>
          <App />
        </BrowserRouter>
      </WalletProvider>
    </ConnectionProvider>
  </React.StrictMode>,
  document.getElementById('root')
);

reportWebVitals();
